INSERT INTO `guide_route` (`id`, `route_name`, `theme`, `cover_url`, `summary`, `description`, `suggest_duration`, `suitable_crowd`, `route_status`, `creator_id`, `create_time`, `update_time`, `deleted`) VALUES
(1, '北京文化深度游', '历史文化', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/e4c794c1fc0c400cab869df18f6deb7a.png', '探索千年古都的文化底蕴', '这条路线将带你深入北京的历史文化核心，从皇家宫殿到现代艺术，感受这座城市的历史与现代交融之美。', '2天', '文化爱好者/家庭', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(2, '西安古都探秘', '历史文化', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/836d362d2cf04cedb76bfa6c7eaa1655.png', '穿越千年，梦回大唐', '西安，十三朝古都，丝绸之路的起点。这条路线将带你领略兵马俑的壮观、古城墙的雄伟、回民街的美食。', '2天', '历史爱好者/亲子', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(3, '杭州诗意之旅', '自然风光', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/eb47d87bb62842c1b842fa309a7cd114.png', '上有天堂，下有苏杭', '漫步西湖边，品味龙井茶，感受杭州的诗意与浪漫。这条路线适合慢慢走、慢慢看。', '1-2天', '情侣/文艺青年', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(4, '云南秘境之旅', '自然风光', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/ff79952a03084405a1f54353c4a151de.png', '从雪山到热带雨林', '丽江古城的悠闲、玉龙雪山的壮美、泸沽湖的神秘，云南给你一段难忘的旅程。', '5-7天', '摄影爱好者/情侣', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(5, '上海摩登都市', '现代都市', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/ad582057e9e543478adbe10ba060faa1.png', '东方明珠的璀璨夜色', '外滩的万国建筑、陆家嘴的摩天大楼、迪士尼的童话世界，感受上海的摩登魅力。', '2-3天', '都市探索者/亲子', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(6, '海南阳光海滩', '海滨度假', 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/route/0192c8ae438f4a3ea389b6f20c9bf487.png', '椰风海韵，阳光沙滩', '亚龙湾的碧海蓝天、蜈支洲岛的潜水天堂、南山寺的佛教文化，享受海南的热带风情。', '4-5天', '度假休闲/家庭', 1, 1, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
