INSERT INTO `scenic_spot` (`id`, `category_id`, `spot_name`, `city`, `address`, `longitude`, `latitude`, `cover_url`, `summary`, `description`, `open_time`, `suggest_duration`, `tips`, `hot_score`, `spot_status`, `creator_id`, `view_count`, `create_time`, `update_time`, `deleted`) VALUES
(1, 2, '故宫博物院', '北京', '北京市东城区景山前街4号', 116.397228, 39.916527, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/2c05551b106c43269c29bd534a5b941d.png', '中国明清两代的皇家宫殿，世界上现存规模最大的宫殿型建筑', '故宫博物院成立于1925年，是以明清两代皇宫和宫廷旧藏文物为基础建立的大型综合性博物馆。占地72万平方米，建筑面积约15万平方米，有大小宫殿七十多座，房屋九千余间。收藏有超过186万件文物，是世界上现存规模最大、保存最为完整的木质结构古建筑之一。', '08:30-17:00（周一闭馆）', '3-4小时', '建议提前网上预约购票，周一闭馆', 999, 1, 1, 15720, '2026-06-16 09:16:50', '2026-06-21 19:41:48', 0),
(2, 2, '秦始皇兵马俑', '西安', '陕西省西安市临潼区秦陵北路', 109.278751, 34.373682, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/728c648b34d545ef9075cef283f3aeb7.png', '世界第八大奇迹，中国第一位皇帝的地下军阵', '兵马俑博物馆是中国最大的古代军事博物馆，位于秦始皇陵东侧1.5公里处。已发掘三座兵马俑坑，面积2万多平方米，出土陶俑、陶马约8000件。每个陶俑的面容、发型、手势各不相同，堪称世界雕塑艺术的瑰宝。', '08:30-18:00', '3-4小时', '旺季建议提前3天预约', 980, 1, 1, 12361, '2026-06-16 09:16:50', '2026-06-18 13:46:23', 0),
(3, 1, '九寨沟', '阿坝', '四川省阿坝藏族羌族自治州九寨沟县', 103.917165, 33.263078, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/7e4414a857ed4807a4fbc50caae6e6c7.png', '人间仙境，童话世界，世界自然遗产', '九寨沟以翠海、叠瀑、彩林、雪峰、藏情、蓝冰六绝著称于世。景区内有114个海子，17个瀑布群，11个溪流，5个钙化滩流。被誉为\"美丽的童话世界\"，1992年被列入世界自然遗产名录。', '全天开放', '1-2天', '海拔较高，注意高原反应；秋季最美', 970, 1, 1, 9872, '2026-06-16 09:16:50', '2026-06-17 16:29:14', 0),
(4, 1, '黄山', '黄山', '安徽省黄山市黄山区汤口镇', 118.168833, 30.137418, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/1c53467d72d3458897f54e8103daa035.png', '五岳归来不看山，黄山归来不看岳', '黄山集名山之长，有泰山之雄伟、华山之险峻、衡山之烟云、庐山之瀑布、雁荡之巧石、峨眉之秀丽。以奇松、怪石、云海、温泉\"四绝\"闻名于世。徐霞客曾赞叹：\"薄海内外无如徽之黄山，登黄山天下无山，观止矣！\"', '06:00-17:30', '2天', '建议住山上看日出日出；冬季注意防滑', 960, 1, 1, 8542, '2026-06-16 09:16:50', '2026-06-17 16:29:19', 0),
(5, 2, '西湖', '杭州', '浙江省杭州市西湖区龙井路1号', 120.148732, 30.242828, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/6676543d57b04d2fbb8db9960f0f1819.png', '欲把西湖比西子，淡妆浓抹总相宜', '西湖位于杭州市区西面，南北长3.3公里，东西宽2.8公里，水面面积约5.66平方公里。环湖四周，绿荫环抱，山色葱茏，画桥烟柳，云树笼纱。西湖十景形成于南宋时期，苏堤春晓、曲院风荷、平湖秋月、断桥残雪等闻名遐迩。2011年列入世界文化遗产。', '全天开放', '1天', '免费开放，建议骑行环湖；夜游也很美', 950, 1, 1, 11201, '2026-06-16 09:16:50', '2026-06-16 19:21:29', 0),
(6, 5, '丽江古城', '丽江', '云南省丽江市古城区', 100.227051, 26.872108, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/676c9191fa24492faa191490379b5a87.png', '东方威尼斯，世界文化遗产', '丽江古城始建于宋末元初，已有800多年历史。古城依山傍水，以水为主，家家流水，户户垂杨。城内街道用五花石铺砌，既有山城风貌，又有水乡韵味。纳西古乐、东巴文化、白沙壁画等人文景观令人流连忘返。', '全天开放', '2-3天', '古城维护费50元；注意防晒', 940, 1, 1, 7652, '2026-06-16 09:16:50', '2026-06-17 14:20:33', 0),
(7, 6, '三亚亚龙湾', '三亚', '海南省三亚市吉阳区亚龙湾', 109.639282, 18.191099, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/6ded811033874880a670fff4c645ffff.png', '天下第一湾，东方夏威夷', '亚龙湾位于三亚市东南28公里处，是海南最南端的一个半月形海湾，全长约7.5公里。这里有蓝天、碧海、白沙、绿林，被誉为\"天下第一湾\"。海水清澈见底，能见度达7-9米，是理想的潜水胜地。', '全天开放', '2-3天', '冬季最佳；注意防晒和水上安全', 930, 1, 1, 6894, '2026-06-16 09:16:50', '2026-06-21 19:02:19', 0),
(8, 4, '上海迪士尼乐园', '上海', '上海市浦东新区川沙镇', 121.667361, 31.143321, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/97283894436f4d288872d2b626691eff.png', '点亮心中奇梦', '上海迪士尼乐园是中国内地首座迪士尼主题乐园，于2016年6月16日开幕。拥有六大主题园区：米奇大街、奇想花园、探险岛、宝藏湾、梦幻世界和明日世界。拥有全球迪士尼主题乐园中最大城堡——奇幻童话城堡。', '08:30-20:30', '1天', '建议工作日前往；下载APP查看排队时间', 920, 1, 1, 13505, '2026-06-16 09:16:50', '2026-06-21 19:47:32', 0),
(9, 3, '上海外滩', '上海', '上海市黄浦区中山东一路', 121.493676, 31.230459, NULL, '万国建筑博览群，上海标志性景观', '外滩位于上海市中心黄浦区的黄浦江畔，是最具上海城市象征意义的景观之一。全长1.5公里，东侧 facing 黄浦江，西侧为52幢风格各异的大楼，被称为\"万国建筑博览群\"。夜晚的外滩灯火辉煌，与对岸的陆家嘴摩天大楼群交相辉映。', '全天开放', '1-2小时', '夜景最美；建议傍晚前往', 910, 1, 1, 10201, '2026-06-16 09:16:50', '2026-06-16 19:22:17', 0),
(10, 1, '张家界国家森林公园', '张家界', '湖南省张家界市武陵源区', 110.479796, 29.326168, NULL, '缩小的仙境，放大的盆景', '张家界国家森林公园是中国第一个国家森林公园，以峰称奇、以谷显幽、以林见秀。三千座石峰拔地而起，八百条溪流蜿蜒曲折。电影《阿凡达》中的悬浮山就是以这里的南天一柱（哈利路亚山）为原型。', '07:00-18:00', '2-3天', '山路较多，穿舒适运动鞋；雨季注意防滑', 900, 1, 1, 7230, '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(11, 1, '测试景点更新-20260616_104620', '杭州', '浙江省杭州市西湖区测试路 1 号', 120.120000, 30.280000, 'https://example.com/test-cover.jpg', '更新后的测试景点摘要', '这是自动化测试脚本创建并更新的景点。', '全天开放', '2小时', '仅用于接口测试', 0, 1, 1, 0, '2026-06-16 10:46:21', '2026-06-16 10:46:21', 1),
(12, 1, '测试景点更新-20260616_110047', '杭州', '浙江省杭州市西湖区测试路 1 号', 120.120000, 30.280000, 'https://example.com/test-cover.jpg', '更新后的测试景点摘要', '这是自动化测试脚本创建并更新的景点。', '全天开放', '2小时', '仅用于接口测试', 0, 1, 1, 0, '2026-06-16 11:00:47', '2026-06-16 11:00:47', 1),
(13, 1, '111', '1', '1', NULL, NULL, '', '', '', '', '1', NULL, 0, 0, 1, 0, '2026-06-17 15:12:29', '2026-06-17 15:12:29', 0),
(14, 2, '北京', '北京', '北京', NULL, NULL, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/4ffec42dab3147989c3e193a61e9babd.png', '北京北京', '', '', '1-2天', NULL, 0, 1, 1, 1, '2026-06-17 17:02:10', '2026-06-21 19:27:15', 0),
(15, 1, '112', '123', '123', NULL, NULL, 'https://communityforum-backendd.oss-cn-hangzhou.aliyuncs.com/scenic/cb47d7c6ebc34c118557e990bc8fc7e2.png', '12', '12', '2', '', NULL, 0, 1, 1, 0, '2026-06-21 19:23:19', '2026-06-21 19:23:19', 0);
INSERT INTO `scenic_spot_i18n` (`id`, `scenic_spot_id`, `language_code`, `title`, `summary`, `description`, `tips`, `create_time`, `update_time`, `deleted`) VALUES
(1, 1, 'en-US', 'The Forbidden City', 'The imperial palace of Chinese emperors', 'The Forbidden City, located in the center of Beijing, was the Chinese imperial palace from the Ming dynasty to the end of the Qing dynasty. It is now home to the Palace Museum.', 'Advance booking recommended. Closed on Mondays.', '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(2, 1, 'ja-JP', '故宮博物院', '中国明清時代の皇宮', '故宮博物院は、明・清時代の皇帝の宮殿を基に設立された博物館です。72万平方メートルの敷地に9000以上の部屋があります。', '事前予約が必要です。月曜日は休館です。', '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(3, 2, 'en-US', 'Terracotta Warriors', 'The Eighth Wonder of the World', 'The Terracotta Army is a collection of terracotta sculptures depicting the armies of Qin Shi Huang, the first Emperor of China.', 'Book tickets 3 days in advance during peak season.', '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(4, 5, 'en-US', 'West Lake', 'A UNESCO World Heritage Site', 'West Lake is a freshwater lake in Hangzhou, China. It has influenced poets and painters throughout Chinese history for its natural beauty and historic relics.', 'Free admission. Cycling around the lake is recommended.', '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(5, 3, 'en-US', 'Jiuzhaigou Valley', 'A Fairyland on Earth', 'Jiuzhaigou is a nature reserve and national park in Sichuan province, famous for its multi-colored lakes, waterfalls, and snow-capped peaks.', 'High altitude - watch for altitude sickness. Autumn is the most beautiful season.', '2026-06-16 09:16:50', '2026-06-16 09:16:50', 0),
(6, 11, 'fr-FR', 'Test Scenic Spot Updated', 'Updated multilingual entry', 'Updated temporary multilingual entry.', 'Still temporary', '2026-06-16 10:46:21', '2026-06-16 10:46:21', 0),
(7, 12, 'fr-FR', 'Test Scenic Spot Updated', 'Updated multilingual entry', 'Updated temporary multilingual entry.', 'Still temporary', '2026-06-16 11:00:47', '2026-06-16 11:00:47', 0);
